function alertSuccess(t){$.alert({title:"Alert!",content:t,type:"green",autoClose:"OK|5000",typeAnimated:!0,buttons:{OK:function(){}}})}function alertWarning(t){$.alert({title:"Alert!",content:t,type:"red",autoClose:"OK|5000",typeAnimated:!0,buttons:{OK:function(){}}})}function alertWithTitle(t,n){$.alert({title:t,content:n,type:"red",autoClose:"OK|5000",typeAnimated:!0,buttons:{OK:function(){}}})}function ConfirmDialog(t,n){$.confirm({title:"Confirm!",content:t+"!",autoClose:"No|10000",buttons:{Yes:function(){n()},No:function(){}}})}